// poliub-frontend/src/context/AuthContext.js
import React, { createContext, useState, useEffect } from "react";
import axios from "axios";

export const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  // 1) Estado para guardar o token JWT e os dados do usuário
  const [token, setToken] = useState(null);
  const [user, setUser] = useState(null);

  // 2) Ao montar o AuthProvider, tenta carregar token de localStorage
  useEffect(() => {
    const tokenEmStorage = localStorage.getItem("token");
    const userEmStorage = localStorage.getItem("user"); // armazenaremos user como JSON-string
    if (tokenEmStorage && userEmStorage) {
      setToken(tokenEmStorage);
      setUser(JSON.parse(userEmStorage));
      // Opcional: configure o default header do axios para todas requisições futuras
      axios.defaults.headers.common["Authorization"] = `Bearer ${tokenEmStorage}`;
    }
  }, []);

  // 3) Função de login: faz POST /api/login, guarda token+user
  const login = async (usuario, senha) => {
    try {
      const response = await axios.post("/api/login", {
        usuario,
        senha,
      });
      // response.data = { token, usuario, role, id, nome, ra, periodo_id }
      const { token: novoToken, id, role, nome, ra, periodo_id } =
        response.data;

      // Guarda token e user no estado
      setToken(novoToken);
      setUser({ id, role, nome, ra, periodo_id, usuario });

      // Também salva no localStorage para persistir após refresh de página
      localStorage.setItem("token", novoToken);
      localStorage.setItem(
        "user",
        JSON.stringify({ id, role, nome, ra, periodo_id, usuario })
      );

      // Configura o header padrão do axios
      axios.defaults.headers.common["Authorization"] = `Bearer ${novoToken}`;

      return { success: true };
    } catch (err) {
      console.error("Erro no login:", err);
      return { success: false, message: err.response?.data?.error || err };
    }
  };

  // 4) Função de logout (limpa tudo)
  const logout = () => {
    setToken(null);
    setUser(null);
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    delete axios.defaults.headers.common["Authorization"];
  };

  return (
    <AuthContext.Provider value={{ token, user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}
